int sk_assign(struct __sk_buff* skb, struct bpf_sock* sk, __u64 flags)
{
  UNITY_LINE_TYPE cmock_line = TEST_LINE_NUM;
  CMOCK_sk_assign_CALL_INSTANCE* cmock_call_instance;
  UNITY_SET_DETAIL(CMockString_sk_assign);
  cmock_call_instance = (CMOCK_sk_assign_CALL_INSTANCE*)CMock_Guts_GetAddressFor(Mock.sk_assign_CallInstance);
  Mock.sk_assign_CallInstance = CMock_Guts_MemNext(Mock.sk_assign_CallInstance);
  if (Mock.sk_assign_IgnoreBool)
  {
    UNITY_CLR_DETAILS();
    if (cmock_call_instance == NULL)
      return Mock.sk_assign_FinalReturn;
    Mock.sk_assign_FinalReturn = cmock_call_instance->ReturnVal;
    return cmock_call_instance->ReturnVal;
  }
  if (!Mock.sk_assign_CallbackBool &&
      Mock.sk_assign_CallbackFunctionPointer != NULL)
  {
    int cmock_cb_ret = Mock.sk_assign_CallbackFunctionPointer(skb, sk, flags, Mock.sk_assign_CallbackCalls++);
    UNITY_CLR_DETAILS();
    return cmock_cb_ret;
  }
  UNITY_TEST_ASSERT_NOT_NULL(cmock_call_instance, cmock_line, CMockStringCalledMore);
  cmock_line = cmock_call_instance->LineNumber;
  if (!cmock_call_instance->ExpectAnyArgsBool)
  {
  if (!cmock_call_instance->IgnoreArg_skb)
  {
    UNITY_SET_DETAILS(CMockString_sk_assign,CMockString_skb);
    UNITY_TEST_ASSERT_EQUAL_MEMORY((void*)(cmock_call_instance->Expected_skb), (void*)(skb), sizeof(struct __sk_buff), cmock_line, CMockStringMismatch);
  }
  if (!cmock_call_instance->IgnoreArg_sk)
  {
    UNITY_SET_DETAILS(CMockString_sk_assign,CMockString_sk);
    UNITY_TEST_ASSERT_EQUAL_MEMORY((void*)(cmock_call_instance->Expected_sk), (void*)(sk), sizeof(struct bpf_sock), cmock_line, CMockStringMismatch);
  }
  if (!cmock_call_instance->IgnoreArg_flags)
  {
    UNITY_SET_DETAILS(CMockString_sk_assign,CMockString_flags);
    UNITY_TEST_ASSERT_EQUAL_MEMORY((void*)(&cmock_call_instance->Expected_flags), (void*)(&flags), sizeof(__u64), cmock_line, CMockStringMismatch);
  }
  }
  if (Mock.sk_assign_CallbackFunctionPointer != NULL)
  {
    cmock_call_instance->ReturnVal = Mock.sk_assign_CallbackFunctionPointer(skb, sk, flags, Mock.sk_assign_CallbackCalls++);
  }
  if (cmock_call_instance->ReturnThruPtr_skb_Used)
  {
    UNITY_TEST_ASSERT_NOT_NULL(skb, cmock_line, CMockStringPtrIsNULL);
    memcpy((void*)skb, (void*)cmock_call_instance->ReturnThruPtr_skb_Val,
      cmock_call_instance->ReturnThruPtr_skb_Size);
  }
  if (cmock_call_instance->ReturnThruPtr_sk_Used)
  {
    UNITY_TEST_ASSERT_NOT_NULL(sk, cmock_line, CMockStringPtrIsNULL);
    memcpy((void*)sk, (void*)cmock_call_instance->ReturnThruPtr_sk_Val,
      cmock_call_instance->ReturnThruPtr_sk_Size);
  }
  UNITY_CLR_DETAILS();
  return cmock_call_instance->ReturnVal;
}

void CMockExpectParameters_sk_assign(CMOCK_sk_assign_CALL_INSTANCE* cmock_call_instance, struct __sk_buff* skb, struct bpf_sock* sk, __u64 flags);
void CMockExpectParameters_sk_assign(CMOCK_sk_assign_CALL_INSTANCE* cmock_call_instance, struct __sk_buff* skb, struct bpf_sock* sk, __u64 flags)
{
  cmock_call_instance->Expected_skb = skb;
  cmock_call_instance->IgnoreArg_skb = 0;
  cmock_call_instance->ReturnThruPtr_skb_Used = 0;
  cmock_call_instance->Expected_sk = sk;
  cmock_call_instance->IgnoreArg_sk = 0;
  cmock_call_instance->ReturnThruPtr_sk_Used = 0;
  memcpy((void*)(&cmock_call_instance->Expected_flags), (void*)(&flags),
         sizeof(__u64[sizeof(flags) == sizeof(__u64) ? 1 : -1])); /* add __u64 to :treat_as_array if this causes an error */
  cmock_call_instance->IgnoreArg_flags = 0;
}

